#include <stdio.h>

static unsigned next_count(void) {
    static unsigned count = 0;
    return ++count;
}

int main(void) {
    unsigned n;
    if (scanf("%u", &n) != 1 || n > 1000u) return 1;
    unsigned result = 0;
    for (unsigned i = 0; i < n; ++i) result = next_count();
    printf("%u\n", result);
    return 0;
}
